import { create } from 'zustand'
import { persist } from 'zustand/middleware'
import type { Message, Conversation } from '@/types'

// Debounce map para updateMessage (evitar centenas de saves durante streaming)
const updateMessageDebounceMap = new Map<string, NodeJS.Timeout>()

interface ChatState {
  conversations: Conversation[]
  activeConversationId: string | null
  isStreaming: boolean
  selectedModel: string
  outputFormat: string // Fase 2: Formato de saída de documentos (docx, pdf, html, txt, md)
  isLoading: boolean

  // Getters
  activeConversation: Conversation | null

  // Actions
  loadConversations: () => Promise<void>
  loadAllConversations: () => Promise<void> // Admin only
  createConversation: () => Promise<Conversation>
  selectConversation: (id: string) => Promise<void>
  deleteConversation: (id: string) => Promise<void>
  renameConversation: (id: string, title: string) => Promise<void>

  addMessage: (message: Omit<Message, 'id' | 'createdAt'>) => Message
  updateMessage: (id: string, content: string) => void
  saveMessageToAPI: (message: Message) => Promise<void>
  setMessageFeedback: (id: string, feedback: 'positive' | 'negative') => void
  addArtifactToMessage: (messageId: string, artifactId: string) => void

  setStreaming: (value: boolean) => void
  setModel: (model: string) => void
  setOutputFormat: (format: string) => void // Fase 2

  clearAll: () => void
}

const generateId = () => Math.random().toString(36).substring(2, 15)

export const useChatStore = create<ChatState>()(
  persist(
    (set, get) => ({
      conversations: [],
      activeConversationId: null,
      isStreaming: false,
      selectedModel: 'auto', // Seleção automática por padrão (economiza custos)
      outputFormat: 'docx', // Fase 2: Word por padrão
      isLoading: false,

      get activeConversation() {
        const state = get()
        return state.conversations.find(c => c.id === state.activeConversationId) || null
      },

      // Carregar conversas do backend (usuário vê apenas suas conversas)
      loadConversations: async () => {
        set({ isLoading: true })
        try {
          const res = await fetch('/api/conversations', {
            credentials: 'include',
          })

          if (res.ok) {
            const data = await res.json()

            if (data.success && data.conversations) {
              // Obter conversas atuais para preservar mensagens já carregadas
              const existingConversations = get().conversations
              const existingMessagesMap = new Map(
                existingConversations.map(c => [c.id, c.messages])
              )

              // Mapear formato do backend para frontend, preservando mensagens existentes
              const conversations = data.conversations.map((c: any) => ({
                id: c.id,
                title: c.title,
                // 🔥 CRÍTICO: Preservar mensagens já carregadas em vez de resetar para []
                messages: existingMessagesMap.get(c.id) || [],
                createdAt: c.created_at,
                updatedAt: c.updated_at,
                model: get().selectedModel,
                // Incluir dados do usuário se disponível (para admin)
                userName: c.user_name,
                userEmail: c.user_email,
              }))

              console.log('📥 loadConversations: Carregadas', conversations.length, 'conversas do usuário')
              console.log('   Mensagens preservadas:', conversations.filter((c: Conversation) => c.messages.length > 0).length)

              set({ conversations, isLoading: false })
            }
          }
        } catch (error) {
          console.error('Erro ao carregar conversas:', error)
          set({ isLoading: false })
        }
      },

      // Carregar TODAS as conversas (apenas admin)
      loadAllConversations: async () => {
        set({ isLoading: true })
        try {
          const res = await fetch('/api/conversations/admin/all', {
            credentials: 'include',
          })

          if (res.ok) {
            const data = await res.json()

            if (data.success && data.conversations) {
              // Obter conversas atuais para preservar mensagens já carregadas
              const existingConversations = get().conversations
              const existingMessagesMap = new Map(
                existingConversations.map(c => [c.id, c.messages])
              )

              // Mapear formato do backend para frontend
              const conversations = data.conversations.map((c: any) => ({
                id: c.id,
                title: c.title,
                messages: existingMessagesMap.get(c.id) || [],
                createdAt: c.created_at,
                updatedAt: c.updated_at,
                model: get().selectedModel,
                userName: c.user_name || 'Anônimo',
                userEmail: c.user_email || '-',
                userId: c.user_id,
              }))

              console.log('📥 loadAllConversations (ADMIN): Carregadas', conversations.length, 'conversas de todos os usuários')

              set({ conversations, isLoading: false })
            }
          } else if (res.status === 403) {
            console.warn('⚠️ Acesso negado ao endpoint admin')
            // Fallback para conversas do usuário
            get().loadConversations()
          }
        } catch (error) {
          console.error('Erro ao carregar todas as conversas:', error)
          set({ isLoading: false })
        }
      },

      createConversation: async () => {
        try {
          const res = await fetch('/api/conversations', {
            method: 'POST',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title: 'Nova conversa' }),
          })

          if (res.ok) {
            const data = await res.json()
            if (data.success && data.conversation) {
              const newConversation: Conversation = {
                id: data.conversation.id,
                title: data.conversation.title,
                messages: [],
                createdAt: data.conversation.created_at,
                updatedAt: data.conversation.updated_at,
                model: get().selectedModel,
              }

              set(state => ({
                conversations: [newConversation, ...state.conversations],
                activeConversationId: newConversation.id,
              }))

              return newConversation
            }
          }
        } catch (error) {
          console.error('Erro ao criar conversa:', error)
        }

        // Fallback para localStorage se API falhar
        const newConversation: Conversation = {
          id: generateId(),
          title: 'Nova conversa',
          messages: [],
          createdAt: new Date().toISOString(),
          updatedAt: new Date().toISOString(),
          model: get().selectedModel,
        }

        set(state => ({
          conversations: [newConversation, ...state.conversations],
          activeConversationId: newConversation.id,
        }))

        return newConversation
      },

      selectConversation: async (id: string) => {
        console.log('🔄 selectConversation chamado:', id)
        set({ activeConversationId: id, isLoading: true })

        try {
          // Buscar mensagens da conversa se ainda não foram carregadas
          const conversation = get().conversations.find(c => c.id === id)
          console.log('   conversation found:', !!conversation)
          console.log('   current messages count:', conversation?.messages?.length || 0)

          if (conversation && conversation.messages.length === 0) {
            console.log('   Fetching messages from API...')
            const res = await fetch(`/api/conversations/${id}`, {
              credentials: 'include',
            })

            if (res.ok) {
              const data = await res.json()
              console.log('   API response:', data.success, 'messages count:', data.conversation?.messages?.length)

              if (data.success && data.conversation) {
                const messages = data.conversation.messages.map((m: any) => {
                  // Parse metadata to extract attachedFiles
                  let attachedFiles: FileInfo[] | undefined
                  if (m.metadata && typeof m.metadata === 'object') {
                    if (m.metadata.attachedFiles && Array.isArray(m.metadata.attachedFiles)) {
                      attachedFiles = m.metadata.attachedFiles
                    }
                  }

                  return {
                    id: m.id,
                    role: m.role,
                    content: m.content,
                    model: m.model,
                    createdAt: m.created_at,
                    isStreaming: false,
                    attachedFiles: attachedFiles,
                  }
                })

                console.log('   ✅ Loaded messages:', messages.length)
                console.log('   📎 Messages with files:', messages.filter((m: any) => m.attachedFiles?.length > 0).length)

                set(state => ({
                  conversations: state.conversations.map(c =>
                    c.id === id ? { ...c, messages } : c
                  ),
                  isLoading: false,
                }))
                return
              }
            } else {
              console.log('   ⚠️ API request failed:', res.status)
            }
          } else if (conversation) {
            console.log('   Skipping fetch - messages already loaded:', conversation.messages.length)
          } else {
            console.log('   ⚠️ Conversation not found in store')
          }
        } catch (error) {
          console.error('Erro ao carregar mensagens:', error)
        }

        set({ isLoading: false })
      },

      deleteConversation: async (id: string) => {
        try {
          const res = await fetch(`/api/conversations/${id}`, {
            method: 'DELETE',
            credentials: 'include',
          })

          if (res.ok) {
            set(state => {
              const newConversations = state.conversations.filter(c => c.id !== id)
              const newActiveId = state.activeConversationId === id
                ? newConversations[0]?.id || null
                : state.activeConversationId

              return {
                conversations: newConversations,
                activeConversationId: newActiveId,
              }
            })
          }
        } catch (error) {
          console.error('Erro ao deletar conversa:', error)
        }
      },

      renameConversation: async (id: string, title: string) => {
        try {
          const res = await fetch(`/api/conversations/${id}`, {
            method: 'PUT',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ title }),
          })

          if (res.ok) {
            set(state => ({
              conversations: state.conversations.map(c =>
                c.id === id ? { ...c, title, updatedAt: new Date().toISOString() } : c
              ),
            }))
          }
        } catch (error) {
          console.error('Erro ao renomear conversa:', error)
        }
      },

      addMessage: (message) => {
        const newMessage: Message = {
          ...message,
          id: generateId(),
          createdAt: new Date().toISOString(),
        }

        console.log('📝 addMessage:', message.role, '- content length:', message.content?.length || 0)

        set(state => {
          const activeId = state.activeConversationId
          if (!activeId) {
            console.log('   ⚠️ No activeConversationId!')
            return state
          }

          // Update conversation title from first user message
          const conversation = state.conversations.find(c => c.id === activeId)
          const shouldUpdateTitle = conversation?.messages.length === 0 && message.role === 'user'
          const newTitle = shouldUpdateTitle
            ? message.content.slice(0, 50) + (message.content.length > 50 ? '...' : '')
            : undefined

          // Auto-rename via API se for primeira mensagem
          if (shouldUpdateTitle && newTitle) {
            get().renameConversation(activeId, newTitle)
          }

          const updatedConversations = state.conversations.map(c =>
            c.id === activeId
              ? {
                  ...c,
                  messages: [...c.messages, newMessage],
                  title: newTitle || c.title,
                  updatedAt: new Date().toISOString(),
                }
              : c
          )

          // Log para debug
          const updatedConv = updatedConversations.find(c => c.id === activeId)
          console.log('   ✅ Message added. Total messages now:', updatedConv?.messages?.length || 0)

          return { conversations: updatedConversations }
        })

        // 🔥 CRÍTICO: Não salvar mensagens vazias (placeholder durante streaming)
        // Elas serão salvas quando updateMessage for chamado com conteúdo real
        if (newMessage.content && newMessage.content.trim() !== '') {
          console.log('   💾 Salvando mensagem no backend...')
          get().saveMessageToAPI(newMessage)
        } else {
          console.log('   ⏭️ Pulando salvamento (mensagem vazia - será salva via updateMessage)')
        }

        return newMessage
      },

      saveMessageToAPI: async (message: Message) => {
        console.log('🔍 saveMessageToAPI called - VERSION 2.0')
        console.log('   role:', message.role)
        console.log('   content length:', message.content?.length || 0)
        console.log('   content preview:', message.content?.substring(0, 50))
        console.log('   attachedFiles count:', message.attachedFiles?.length || 0)

        const activeId = get().activeConversationId
        if (!activeId) {
          console.log('   ⚠️ No activeConversationId, skipping save')
          return
        }

        // Não salvar mensagens vazias (streaming em progresso)
        if (!message.content || message.content.trim() === '') {
          console.log('   ⏭️ Mensagem vazia, pulando salvamento (streaming em progresso)')
          return
        }

        console.log('   ✅ Validation passed, sending to API...')

        try {
          const response = await fetch(`/api/conversations/${activeId}/messages`, {
            method: 'POST',
            credentials: 'include',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({
              role: message.role,
              content: message.content,
              model: message.model,
              attachedFiles: message.attachedFiles || [],
            }),
          })

          if (!response.ok) {
            console.error('   ❌ API returned error:', response.status)
            const errorText = await response.text()
            console.error('   Error details:', errorText)
          } else {
            console.log('   ✅ Message saved successfully to backend')
          }
        } catch (error) {
          console.error('   ❌ Erro ao salvar mensagem:', error)
        }
      },

      updateMessage: (id: string, content: string) => {
        set(state => ({
          conversations: state.conversations.map(c =>
            c.id === state.activeConversationId
              ? {
                  ...c,
                  messages: c.messages.map(m =>
                    m.id === id ? { ...m, content, isStreaming: false } : m
                  ),
                  updatedAt: new Date().toISOString(),
                }
              : c
          ),
        }))

        // Smart debounce during streaming
        const isCurrentlyStreaming = get().isStreaming

        if (!isCurrentlyStreaming) {
          const message = get().activeConversation?.messages.find(m => m.id === id)
          if (message && content && content.trim() !== '') {
            // Debounce para evitar múltiplas chamadas rápidas
            const existingTimeout = updateMessageDebounceMap.get(id)
            if (existingTimeout) {
              clearTimeout(existingTimeout)
            }
            const newTimeout = setTimeout(() => {
              get().saveMessageToAPI({ ...message, content })
              updateMessageDebounceMap.delete(id)
            }, 1000) // Aguardar 1s após última atualização
            updateMessageDebounceMap.set(id, newTimeout)
          }
        }
      },

      setMessageFeedback: (id: string, feedback: 'positive' | 'negative') => {
        set(state => ({
          conversations: state.conversations.map(c =>
            c.id === state.activeConversationId
              ? {
                  ...c,
                  messages: c.messages.map(m =>
                    m.id === id ? { ...m, feedback } : m
                  ),
                }
              : c
          ),
        }))
      },

      addArtifactToMessage: (messageId: string, artifactId: string) => {
        set(state => ({
          conversations: state.conversations.map(c =>
            c.id === state.activeConversationId
              ? {
                  ...c,
                  messages: c.messages.map(m =>
                    m.id === messageId
                      ? { ...m, artifacts: [...(m.artifacts || []), artifactId] }
                      : m
                  ),
                }
              : c
          ),
        }))
      },

      setStreaming: (value: boolean) => set({ isStreaming: value }),

      setModel: (model: string) => set({ selectedModel: model }),

      setOutputFormat: (format: string) => set({ outputFormat: format }), // Fase 2

      clearAll: () => set({ conversations: [], activeConversationId: null }),
    }),
    {
      name: 'rom-chat',
      partialize: (state) => ({
        // Manter cache local mas não substituir dados da API
        activeConversationId: state.activeConversationId,
        selectedModel: state.selectedModel,
        outputFormat: state.outputFormat, // Fase 2: Persistir formato escolhido
      }),
    }
  )
)
